import { AppState, UserProfile, UserStats, LearningMaterial } from '../types';

const STORAGE_KEY = 'studygenie_data';

const DEFAULT_STATS: UserStats = {
  accuracy: 0,
  speed: 0,
  retention: 0,
  consistency: 0,
  totalQuizzes: 0,
  weakTopics: []
};

export const storageService = {
  saveState: (state: Partial<AppState>) => {
    const current = storageService.getState();
    const updated = { ...current, ...state };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
  },

  getState: (): AppState => {
    const data = localStorage.getItem(STORAGE_KEY);
    if (!data) return { user: null, materials: [], stats: DEFAULT_STATS, isDarkMode: false };
    return JSON.parse(data);
  },

  clear: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Concept, QuizQuestion, Difficulty } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async extractConcepts(content: string, type: 'pdf' | 'video' | 'text'): Promise<{ summary: string; concepts: Concept[] }> {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this ${type} content and extract key concepts. Provide a concise summary and a structured list of concepts with descriptions and their relationships.

      Content: ${content.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            concepts: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  name: { type: Type.STRING },
                  description: { type: Type.STRING },
                  connections: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["id", "name", "description", "connections"]
              }
            }
          },
          required: ["summary", "concepts"]
        }
      }
    });

    const data = JSON.parse(response.text);
    return {
      summary: data.summary,
      concepts: data.concepts.map((c: any) => ({ ...c, mastery: 1 }))
    };
  },

  async generateQuiz(materialContent: string, difficulty: Difficulty): Promise<QuizQuestion[]> {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a 5-question multiple choice quiz based on the following material. Difficulty level: ${difficulty}.

      Material: ${materialContent.substring(0, 5000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswer: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ["id", "question", "options", "correctAnswer", "explanation"]
          }
        }
      }
    });

    const questions = JSON.parse(response.text);
    return questions.map((q: any) => ({ ...q, difficulty }));
  }
};

