interface LearningHubProps {
  onMaterialProcessed: (material: LearningMaterial) => void;
}

const LearningHub: React.FC<LearningHubProps> = ({ onMaterialProcessed }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [status, setStatus] = useState<string>('');

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'pdf' | 'video' | 'text') => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setStatus('Reading file...');

    // In a real app, we'd extract text from PDF or transcribe audio.
    // Here we simulate the process and send a mock "content" to Gemini.
    setTimeout(async () => {
      setStatus('Analyzing with AI...');
      const mockContent = `This is a long educational content about ${file.name.split('.')[0]}. It covers various aspects, history, and key principles related to the topic. Fundamental concepts include efficiency, organization, and systematic review.`;

      try {
        const { summary, concepts } = await geminiService.extractConcepts(mockContent, type);

        const newMaterial: LearningMaterial = {
          id: Math.random().toString(36).substr(2, 9),
          title: file.name.replace(/\.[^/.]+$/, ""),
          type,
          content: mockContent,
          summary,
          concepts,
          createdAt: new Date().toISOString()
        };

        setStatus('Finalizing concept map...');
        setTimeout(() => {
          onMaterialProcessed(newMaterial);
          setIsProcessing(false);
          setStatus('');
        }, 1000);
      } catch (err) {
        console.error(err);
        setStatus('Error processing material');
        setTimeout(() => setIsProcessing(false), 2000);
      }
    }, 1500);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-bold text-gray-900">Level Up Your Knowledge</h2>
