import React, { useState, useEffect } from 'react';
import { QuizQuestion, Difficulty, UserProfile } from '../types';
import { Zap, CheckCircle2, XCircle, ArrowRight, Trophy } from 'lucide-react';
import { geminiService } from '../services/geminiService';
import { DIFFICULTY_MULTIPLIERS } from '../constants';

interface QuizProps {
  materialId: string;
  materialContent: string;
  user: UserProfile;
  onComplete: (score: number, xpGained: number) => void;
}

const Quiz: React.FC<QuizProps> = ({ materialContent, user, onComplete }) => {
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchQuiz = async () => {
      try {
        const q = await geminiService.generateQuiz(materialContent, Difficulty.MEDIUM);
        setQuestions(q);
        setLoading(false);
      } catch (err) {
        console.error(err);
      }
    };
    fetchQuiz();
  }, [materialContent]);

  const handleAnswer = (idx: number) => {
    if (isAnswered) return;
    setSelectedOption(idx);
    setIsAnswered(true);
    if (idx === questions[currentIndex].correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const nextQuestion = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setSelectedOption(null);
      setIsAnswered(false);
    } else {
      const multiplier = DIFFICULTY_MULTIPLIERS[Difficulty.MEDIUM];
      const xpGained = Math.round(score * 50 * multiplier);
      onComplete(score, xpGained);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-4">
        <Zap className="text-yellow-400 animate-pulse" size={48} />
        <h3 className="text-xl font-bold">Generating adaptive quiz...</h3>
      </div>
    );
  }

  const currentQ = questions[currentIndex];
  const progress = ((currentIndex + 1) / questions.length) * 100;

  return (
    <div className="max-w-2xl mx-auto animate-in slide-in-from-right duration-500">
      <div className="mb-8 space-y-4">
        <div className="flex justify-between items-center text-sm text-gray-500 font-medium">
          <span>Question {currentIndex + 1} of {questions.length}</span>
          <span>{Math.round(progress)}% Complete</span>
        </div>
        <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-indigo-600 transition-all duration-500"
            style={{ width: `${progress}%` }}
          ></div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-8">
        <h3 className="text-2xl font-bold text-gray-900 leading-tight">
          {currentQ.question}
        </h3>

        <div className="space-y-4">
          {currentQ.options.map((option, idx) => {
            let bgColor = "bg-white border-gray-200 hover:border-indigo-600";
            if (isAnswered) {
              if (idx === currentQ.correctAnswer) bgColor = "bg-emerald-50 border-emerald-500 text-emerald-700";
              else if (idx === selectedOption) bgColor = "bg-red-50 border-red-500 text-red-700";
              else bgColor = "bg-gray-50 border-gray-200 opacity-50";
            } else if (selectedOption === idx) {
              bgColor = "bg-indigo-50 border-indigo-600 text-indigo-700";
            }

            return (
              <button
                key={idx}
                disabled={isAnswered}
                onClick={() => handleAnswer(idx)}
                className={`w-full text-left p-5 rounded-2xl border-2 transition-all font-medium flex items-center justify-between ${bgColor}`}
              >
                <span>{option}</span>
                {isAnswered && idx === currentQ.correctAnswer && <CheckCircle2 size={20} />}
                {isAnswered && idx === selectedOption && idx !== currentQ.correctAnswer && <XCircle size={20} />}
              </button>
            );
          })}
        </div>

        {isAnswered && (
          <div className="animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="p-5 bg-indigo-50/50 rounded-2xl text-sm text-indigo-800 leading-relaxed border border-indigo-100 mb-6">
              <span className="font-bold block mb-1">Explanation</span>
              {currentQ.explanation}
            </div>
            <button
              onClick={nextQuestion}
              className="w-full py-4 bg-gray-900 text-white rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-black transition-colors"
            >
              {currentIndex === questions.length - 1 ? "Finish Quiz" : "Next Question"}
              <ArrowRight size={20} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Quiz;

