interface LearningHubProps {
  onMaterialProcessed: (material: LearningMaterial) => void;
}

const LearningHub: React.FC<LearningHubProps> = ({ onMaterialProcessed }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [status, setStatus] = useState<string>('');

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'pdf' | 'video' | 'text') => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setStatus('Reading file...');

    // In a real app, we'd extract text from PDF or transcribe audio.
    // Here we simulate the process and send a mock "content" to Gemini.
    setTimeout(async () => {
      setStatus('Analyzing with AI...');
      const mockContent = `This is a long educational content about ${file.name.split('.')[0]}. It covers various aspects, history, and key principles related to the topic. Fundamental concepts include efficiency, organization, and systematic review.`;

      try {
        const { summary, concepts } = await geminiService.extractConcepts(mockContent, type);

        const newMaterial: LearningMaterial = {
          id: Math.random().toString(36).substr(2, 9),
          title: file.name.replace(/\.[^/.]+$/, ""),
          type,
          content: mockContent,
          summary,
          concepts,
          createdAt: new Date().toISOString()
        };

        setStatus('Finalizing concept map...');
        setTimeout(() => {
          onMaterialProcessed(newMaterial);
          setIsProcessing(false);
          setStatus('');
        }, 1000);
      } catch (err) {
        console.error(err);
        setStatus('Error processing material');
        setTimeout(() => setIsProcessing(false), 2000);
      }
    }, 1500);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-bold text-gray-900">Level Up Your Knowledge</h2>
        <p className="text-gray-500">Upload your study material and let StudyGenie extract the magic.</p>
      </div>

      {isProcessing ? (
        <div className="bg-white p-12 rounded-[2rem] border-2 border-dashed border-indigo-100 flex flex-col items-center justify-center space-y-6 text-center">
          <div className="relative">
            <Loader2 className="animate-spin text-indigo-600" size={64} />
            <BrainCircuit className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-indigo-400" size={24} />
          </div>
          <div>
            <h3 className="text-xl font-bold text-gray-900">{status}</h3>
            <p className="text-gray-500">Our neural engine is busy parsing concepts...</p>
          </div>
          <div className="w-full max-w-xs h-1.5 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-600 animate-pulse w-3/4"></div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <label className="group relative bg-white p-8 rounded-[2rem] border-2 border-dashed border-gray-200 hover:border-indigo-400 hover:bg-indigo-50/30 transition-all cursor-pointer flex flex-col items-center text-center">
            <input type="file" className="hidden" accept=".pdf" onChange={(e) => handleFileUpload(e, 'pdf')} />
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
              <FileText size={32} />
            </div>
            <h3 className="font-bold text-gray-900 text-lg">Upload PDF</h3>
            <p className="text-gray-400 text-sm mt-1">Extract text & concepts automatically</p>
          </label>

          <label className="group relative bg-white p-8 rounded-[2rem] border-2 border-dashed border-gray-200 hover:border-indigo-400 hover:bg-indigo-50/30 transition-all cursor-pointer flex flex-col items-center text-center">
            <input type="file" className="hidden" accept="video/*" onChange={(e) => handleFileUpload(e, 'video')} />
            <div className="w-16 h-16 bg-blue-50 text-blue-500 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
              <Video size={32} />
            </div>
            <h3 className="font-bold text-gray-900 text-lg">Upload Video</h3>
            <p className="text-gray-400 text-sm mt-1">Transcribe & summarize key points</p>
          </label>
        </div>
      )}

      <div className="bg-indigo-900 rounded-[2.5rem] p-8 text-white relative overflow-hidden">
        <div className="relative z-10 space-y-4">
          <div className="inline-flex items-center gap-2 bg-indigo-800/50 px-4 py-1.5 rounded-full text-sm font-medium border border-indigo-700">
            <Zap size={16} className="text-yellow-400" />
