import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, LearningMaterial } from '../types';
import { Send, Sparkles, Brain, Book, Zap, Trash2 } from 'lucide-react';
import { geminiService } from '../services/geminiService';

interface AITutorProps {
  materials: LearningMaterial[];
  chatHistory: ChatMessage[];
  onUpdateChat: (chat: ChatMessage[]) => void;
}

const AITutor: React.FC<AITutorProps> = ({ materials, chatHistory, onUpdateChat }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [chatHistory, isTyping]);

  const handleSend = async (text: string) => {
    if (!text.trim()) return;
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text, timestamp: new Date().toISOString() };
    const updatedChat = [...chatHistory, userMsg];
    onUpdateChat(updatedChat);
    setInput('');
    setIsTyping(true);

    // Simulate AI response using the concepts of the most recent material
    const context = materials[0]?.content || "general knowledge";

    setTimeout(() => {
      const aiMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'assistant', 
        text: `Based on your materials regarding "${materials[0]?.title || 'learning'}", I'd be happy to explain that. In simple terms, it's about neural connections being reinforced through spaced repetition. Would you like a real-life example or a mini-test?`,
        timestamp: new Date().toISOString() 
      };
      onUpdateChat([...updatedChat, aiMsg]);
      setIsTyping(false);
    }, 1500);
  };

  const clearChat = () => {
    onUpdateChat([]);
  };

  return (
    <div className="h-[calc(100vh-200px)] flex flex-col animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h2 className="text-xl font-black text-gray-900 tracking-tight flex items-center gap-2">
            AI Tutor <Sparkles className="text-indigo-600" size={18} />
          </h2>
          <p className="text-xs text-gray-400 font-medium">Context: {materials[0]?.title || 'General'}</p>
        </div>
        <button onClick={clearChat} className="p-2 text-gray-300 hover:text-red-500"><Trash2 size={18} /></button>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-6 scrollbar-hide mb-4 px-1">
        {chatHistory.length === 0 && (
          <div className="py-20 text-center space-y-4">
            <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center mx-auto"><Brain size={32} /></div>
            <h3 className="text-lg font-black text-gray-900">What shall we explore today?</h3>
            <p className="text-sm text-gray-400 max-w-xs mx-auto">Ask me about your uploaded materials or test your knowledge.</p>
          </div>
        )}

        {chatHistory.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-5 rounded-3xl text-sm font-medium leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none shadow-lg' 
                : 'bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 border border-gray-100 dark:border-gray-700 rounded-tl-none shadow-sm'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
             <div className="bg-white dark:bg-gray-800 p-4 rounded-3xl border border-gray-100 dark:border-gray-700 flex gap-1">
               <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce" />
               <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce delay-75" />
               <div className="w-1.5 h-1.5 bg-gray-300 rounded-full animate-bounce delay-150" />
             </div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {/* Quick Actions */}
        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button onClick={() => handleSend("Explain simply")} className="px-4 py-2 bg-white rounded-full text-[10px] font-black uppercase tracking-widest text-gray-500 border border-gray-100 shrink-0 hover:border-indigo-600 transition-all flex items-center gap-1"><Book size={12}/> Explain Simply</button>
          <button onClick={() => handleSend("Real-life example")} className="px-4 py-2 bg-white rounded-full text-[10px] font-black uppercase tracking-widest text-gray-500 border border-gray-100 shrink-0 hover:border-indigo-600 transition-all flex items-center gap-1"><Zap size={12}/> Real Example</button>
          <button onClick={() => handleSend("Test me")} className="px-4 py-2 bg-white rounded-full text-[10px] font-black uppercase tracking-widest text-gray-500 border border-gray-100 shrink-0 hover:border-indigo-600 transition-all flex items-center gap-1"><Brain size={12}/> Test Me</button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); handleSend(input); }} className="relative">
          <input 
